diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index c1ce364eb179..bd1d1844dadc 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1516,6 +1516,7 @@ static Instruction *foldBoxMultiply(BinaryOperator &I) {
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   if (Value *V = simplifyAddInst(I.getOperand(0), I.getOperand(1),
                                  I.hasNoSignedWrap(), I.hasNoUnsignedWrap(),
@@ -1564,6 +1565,43 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   if (Ty->isIntOrIntVectorTy(1))
     return BinaryOperator::CreateXor(LHS, RHS);

+  // Fold ceil unsigned division by a power-of-two:
+  // (X >> ShAmt) + zext((X & ((1 << ShAmt) - 1)) != 0) --> (X + ((1 << ShAmt)-1)) >> ShAmt
+  {
+    Value *X, *AndX;
+    const APInt *ShAmt, *Mask;
+    CmpPredicate Pred;
+    auto MatchCeilUDivPow2 = [&](Value *ShiftV, Value *ExtV) -> Instruction * {
+      if (!match(ShiftV, m_LShr(m_Value(X), m_APInt(ShAmt))))
+        return nullptr;
+
+      if (!match(ExtV, m_ZExt(m_ICmp(Pred, m_And(m_Value(AndX), m_APInt(Mask)),
+                                    m_ZeroInt()))))
+        return nullptr;
+
+      if (Pred != ICmpInst::ICMP_NE || X != AndX)
+        return nullptr;
+
+      unsigned BW = X->getType()->getScalarSizeInBits();
+      if (ShAmt->uge(BW))
+        return nullptr;
+
+      APInt ExpectedMask = APInt::getLowBitsSet(Mask->getBitWidth(),
+                                                ShAmt->getZExtValue());
+      if (*Mask != ExpectedMask)
+        return nullptr;
+
+      Value *Add = Builder.CreateAdd(X, ConstantInt::get(X->getType(), *Mask));
+      return BinaryOperator::CreateLShr(Add,
+                                        ConstantInt::get(X->getType(), *ShAmt));
+    };
+
+    if (Instruction *R = MatchCeilUDivPow2(LHS, RHS))
+      return R;
+    if (Instruction *R = MatchCeilUDivPow2(RHS, LHS))
+      return R;
+  }
+
   // X + X --> X << 1
   if (LHS == RHS) {
     auto *Shl = BinaryOperator::CreateShl(LHS, ConstantInt::get(Ty, 1));
@@ -1893,6 +1931,7 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   return Changed ? &I : nullptr;
 }

+
 /// Eliminate an op from a linear interpolation (lerp) pattern.
 static Instruction *factorizeLerp(BinaryOperator &I,
                                   InstCombiner::BuilderTy &Builder) {

